import { ENTITIES } from "./constants.js";

export function escapeSvelte(str: string): string {
	return (
		str
			// @ts-expect-error TODO: not sure why this is erroring,
			// but we should be mindful of it incase there's a JS incompatibility issue with >=node18
			.replace(/[{}`]/g, (c) => {
				if (c === "{") return ENTITIES.LEFT_CURLY;
				if (c === "}") return ENTITIES.RIGHT_CURLY;
				if (c === "`") return ENTITIES.BACK_TICK;
			})
			.replace(/\\([trn])/g, "&#92;$1")
	);
}

export { ENTITIES };
