import fs from 'node:fs';
import path from 'node:path';
import { visit } from 'unist-util-visit';
import { toHtml } from 'hast-util-to-html';
import { escapeSvelte } from '@mdsx/common';
import { parse, preprocess } from 'svelte/compiler';
import { extractNamedExports, logPerf } from '../utils.js';
import { MDSX_COMPONENT_NAME } from '../constants.js';
import type { Element, Root } from 'hast';
import type { Transformer } from 'unified';
import type { FileData } from '../types.js';

type HastTransformer = Transformer<Root, Root>;

/**
 * Renders `<pre>` elements as HTML so they can be used within Svelte components.
 */
export function rehypeRenderCode(): HastTransformer {
	return (tree) => {
		visit(tree, 'element', (node) => {
			const tags = ['pre', 'code'];
			if (!tags.includes(node.tagName)) return;

			let codeEl: Element | undefined;
			if (node.tagName === 'pre') {
				codeEl = node.children[0] as Element;
				if (!codeEl || codeEl.type !== 'element' || codeEl.tagName !== 'code') return;
			} else {
				codeEl = node;
			}
			const codeString = toHtml(codeEl, {
				characterReferences: { useNamedReferences: true },
			});

			// @ts-expect-error Change the node type to raw...
			codeEl.type = 'raw';
			// @ts-expect-error ...and insert the content
			codeEl.value = `{@html \`${escapeSvelte(codeString)}\`}`;
		});
	};
}

// blueprint will be constructed at this step of the pipeline
export function rehypeBuildBlueprint(): HastTransformer {
	return async (tree, file) => {
		const a = performance.now();
		const data = file.data as FileData;
		const blueprint = data.blueprint;
		if (blueprint === undefined) return;

		const source = fs.readFileSync(blueprint.path, { encoding: 'utf8' });
		const filename = path.parse(blueprint.path).base;

		const { code, dependencies } = await preprocess(source, data.preprocessors, { filename });
		if (dependencies) data.dependencies.push(...dependencies);

		const ast = parse(code, { filename });

		const module = ast.module;
		if (module === undefined) {
			throw new Error(
				`Blueprint "${blueprint.name}" at path "${blueprint.path}" is missing it's exported components - See TODO: Add a link to docs here`
			);
		}

		const namedExports = extractNamedExports(module);
		if (namedExports.length > 0) {
			data.components = namedExports;
		}
		logPerf('rehypeBuildBlueprint', a);
	};
}

export function rehypeSvelteOverrideComponents(): HastTransformer {
	return (tree, file) => {
		const a = performance.now();
		const data = file.data as FileData;
		if (!data.blueprint) return;

		const components = data.components;
		if (!components) return;

		visit(tree, 'element', (node) => {
			if (components.includes(node.tagName)) {
				node.tagName = `${MDSX_COMPONENT_NAME}.${node.tagName}`;
			}
		});
		logPerf('rehypeSvelteOverrideComponents', a);
	};
}
