import path from 'node:path';
import { walk } from 'zimmerframe';
import { print } from 'esrap';
import { VFile } from 'vfile';
import { MDSX_BLUEPRINT_NAME, MDSX_COMPONENT_NAME } from './constants.js';
import type { Node } from 'estree';
import type { Ast } from 'svelte/types/compiler/interfaces';
import type { MDSXConfig } from './defineConfig.js';
import type { FileData } from './types.js';

function toPOSIX(joinedPath: string): string {
	const a = performance.now();
	const isExtendedLengthPath = /^\\\\\?\\/.test(joinedPath);
	const hasNonAscii = /[^\0-\x80]+/.test(joinedPath);

	if (isExtendedLengthPath || hasNonAscii) {
		return joinedPath;
	}

	logPerf('toPOSIX', a);

	return joinedPath.replace(/\\/g, '/');
}

/**
 *
 * @param from Absolute file path of the starting point
 * @param to Absolute file path of target
 * @returns The relative file path of {to} from {from} in POSIX format
 */
export function getRelativeFilePath(from: string, to: string) {
	const transformedA = path.resolve(from, '..');
	const relativePath = toPOSIX(path.relative(transformedA, to));

	if (!relativePath.startsWith('.')) {
		return `./${relativePath}`;
	}

	return relativePath;
}

type Script = NonNullable<Ast['module']>;

/**
 * Extract the names of the exported components from a Svelte
 * module AST.
 *
 * @param ast The `module` AST of the component
 * @returns An array of the exported component names
 */
export function extractNamedExports(ast: Script) {
	const a = performance.now();
	const exportedComponentNames: string[] = [];

	const state = {};
	walk(ast.content as Node, state, {
		ExportNamedDeclaration(node) {
			for (const specifier of node.specifiers) {
				exportedComponentNames.push(specifier.exported.name);
			}
		},
	});

	logPerf('extractNamedExports', a);

	return exportedComponentNames;
}

/**
 * Creates or updates the Svelte instance script tag
 * to import the blueprint component, as well as any
 * components exported from the blueprint.
 *
 * @param ast The `instance` AST of the markdown component
 * @param filePath The absolute file path of the markdown component
 * @param blueprintPath The absolute file path of the blueprint component
 * @returns
 */
export function updateOrCreateSvelteInstance(
	ast: Script | undefined,
	filePath: string,
	blueprintPath: string
) {
	const a = performance.now();
	const importStatement = `import ${MDSX_BLUEPRINT_NAME}, * as ${MDSX_COMPONENT_NAME} from "${getRelativeFilePath(filePath, blueprintPath)}"`;

	// if no AST is provided, we create a new script tag
	if (!ast) {
		const content = `<script>${importStatement}</script>`;
		logPerf('updateOrCreateSvelteInstance', a);
		return {
			start: 0,
			end: 0,
			content,
		};
	}

	// if an AST is provided, we update the existing script tag
	const { code } = print(ast.content);
	const content = `<script>\n${importStatement}\n${code}\n</script>`;

	logPerf('updateOrCreateSvelteInstance', a);
	return {
		start: ast.start,
		end: ast.end,
		content,
	};
}

/**
 * Creates or updates the Svelte module script tag
 * to export and destructure the frontmatter metadata
 * object so it can be used in the component and passed
 * to the blueprint component via props.
 *
 * @param ast The `module` AST of the markdown component
 * @param data The data from the vfile
 * @returns
 */
export function updateOrCreateSvelteModule(ast: Script | undefined, data: FileData) {
	const a = performance.now();
	const metadataStr = JSON.stringify(data.matter);

	// I think we still export an empty metadata object, even if there is no frontmatter
	const exportStatement = `export const metadata = ${metadataStr};\n`;

	const metadataKeys = Object.keys(data.matter);
	let metadataDeclaration: string | undefined = undefined;

	// Only destructure the metadata if the keys are present
	if (metadataKeys.length > 0) {
		metadataDeclaration = `const { ${metadataKeys.join(', ')} } = metadata;`;
	}

	const statement = exportStatement + (metadataDeclaration ?? '');

	// if no module AST is provided, we create a new script module tag
	if (!ast) {
		const content = `<script module>${statement}</script>`;
		logPerf('updateOrCreateSvelteModule', a);
		return {
			start: 0,
			end: 0,
			content,
		};
	}

	// if a module AST is provided, we update the existing script module tag
	const { code } = print(ast.content);
	const content = `<script module>\n${statement}\n${code}\n</script>`;

	logPerf('updateOrCreateSvelteModule', a);

	return {
		start: ast.start,
		end: ast.end,
		content,
	};
}

/**
 * Retrieves the relevant blueprint data from the VFile's
 * frontmatter.
 *
 * @param file The VFile to be processed via the `unified` pipeline
 * @param config The MDSX config object
 * @returns blueprint data used to process the VFile
 */
export function getBlueprintData(file: VFile, config?: MDSXConfig) {
	if (!config?.blueprints) return;
	const a = performance.now();

	const data = file.data as FileData;
	const blueprintName = data.matter?.blueprint ?? 'default';

	// if `blueprint: false`, don't use the default blueprint
	if (blueprintName === false) return;

	if (typeof blueprintName !== 'string') {
		throw new Error(`The "blueprint" name in the frontmatter must be a string in "${file.path}"`);
	}

	const blueprint = config.blueprints[blueprintName];
	if (blueprint === undefined) {
		throw Error(
			`Blueprint "${blueprintName}" is not defined in the blueprint map in the MDSX config`
		);
	}

	logPerf('getBlueprintData', a);

	return Object.assign(blueprint, {
		name: blueprintName,
		remarkPlugins: blueprint.remarkPlugins ?? [],
		rehypePlugins: blueprint.rehypePlugins ?? [],
	});
}

export function logPerf(name: string, startTime: number) {
	if (process.env?.MDSX_LOG_LEVEL === 'debug') {
		console.log(`${name}: `, performance.now() - startTime);
	}
}
