import MagicString from 'magic-string';
import { VFile } from 'vfile';
import { parse, preprocess } from 'svelte/compiler';
import { MDSX_BLUEPRINT_NAME } from './constants.js';
import { matter } from './matter.js';
import {
	getBlueprintData,
	logPerf,
	updateOrCreateSvelteInstance,
	updateOrCreateSvelteModule,
} from './utils.js';
import type { PreprocessorGroup, Processed } from 'svelte/compiler';
import type { MDSXConfig } from './defineConfig.js';
import type { FileData } from './types.js';

// unified plugins
import { unified } from 'unified';
import remarkParse from 'remark-parse';
import remarkRehype from 'remark-rehype';
import rehypeStringify from 'rehype-stringify';
import {
	rehypeBuildBlueprint,
	rehypeRenderCode,
	rehypeSvelteOverrideComponents,
} from './plugins/rehype.js';
import { remarkCleanSvelte } from './plugins/remark.js';

type CompileOptions = {
	config?: MDSXConfig;
	filename?: string;
	preprocessors: PreprocessorGroup[];
};
export async function compile(
	source: string,
	{ config, filename, preprocessors }: CompileOptions
): Promise<Processed> {
	const a = performance.now();

	const remarkPlugins = config?.remarkPlugins ?? [];
	const rehypePlugins = config?.rehypePlugins ?? [];

	const file = new VFile({
		value: source,
		path: filename,
		data: {
			remarkPlugins,
			rehypePlugins,
			dependencies: [],
			instance: undefined,
			preprocessors,
			matter: {},
		},
	});

	// attach frontmatter to vfile
	matter(file, config?.frontmatterParser);

	const data = file.data as FileData;
	const blueprint = getBlueprintData(file, config);
	if (blueprint) {
		// add the Blueprint to the dependencies so that updates to them can be tracked
		data.dependencies.push(blueprint.path);
		// attach to the vfile
		data.blueprint = blueprint;
		remarkPlugins.push(...blueprint.remarkPlugins);
		rehypePlugins.push(...blueprint.rehypePlugins);
	}

	const processed = await unified()
		.use(remarkParse)
		.use(remarkCleanSvelte)
		// user supplied remark plugins
		.use(remarkPlugins)
		// converts MD -> HTML
		.use(remarkRehype, { allowDangerousHtml: true })
		// user supplied rehype plugins
		.use(rehypePlugins)
		.use(rehypeRenderCode)
		// this needs to be renamed
		.use(rehypeBuildBlueprint)
		.use(rehypeSvelteOverrideComponents)
		.use(rehypeStringify, { allowDangerousHtml: true })
		.process(file);

	const { code, dependencies } = await preprocess(String(processed), preprocessors, { filename });
	if (dependencies) data.dependencies.push(...dependencies);

	const ms = new MagicString(code);
	const parsed = parse(code);
	const module = updateOrCreateSvelteModule(parsed.module, data);

	if (blueprint) {
		let cssContent: string | undefined;
		const instance = updateOrCreateSvelteInstance(parsed.instance, file.path, blueprint.path);

		// We want to remove and hoist the instance, module, and css.
		// The remaining html will be wrapped with the Blueprint's component tag.
		if (parsed.instance) {
			ms.remove(parsed.instance.start, parsed.instance.end);
		}
		if (parsed.module) {
			ms.remove(parsed.module.start, parsed.module.end);
		}
		if (parsed.css) {
			cssContent = ms.original.substring(parsed.css.start, parsed.css.end);
			ms.remove(parsed.css.start, parsed.css.end);
		}

		// wrap the html content with the Blueprint
		ms.prepend(`<${MDSX_BLUEPRINT_NAME} {metadata}>\n`);
		ms.append(`</${MDSX_BLUEPRINT_NAME}>\n`);

		// now we put them back up to the top
		if (cssContent) ms.prepend(cssContent);
		// we always have an instance when a Blueprint is used
		ms.prepend(instance.content);
	}

	// this is prepended outside of the above block as the module
	// isn't dependent on the presence of a Blueprint
	ms.prepend(module.content);

	logPerf('processMarkdown', a);

	return {
		code: ms.toString(),
		map: ms.generateMap({ source: filename }),
		dependencies: data.dependencies,
	};
}
