// Code modified and adapted from: https://github.com/vfile/vfile-matter/blob/main/lib/index.js

import yaml from 'yaml';
import { VFile } from 'vfile';
import { logPerf } from './utils.js';
import type { MDSXConfig } from './defineConfig.js';

const regex = /^---(?:\r?\n|\r)(?:([\s\S]*?)(?:\r?\n|\r))?---(?:\r?\n|\r|$)/;

/**
 * Parse the YAML front matter in a file and expose it as `file.data.matter`.
 *
 * If no matter is found in the file, nothing happens, except that
 * `file.data.matter` is set to an empty object (`{}`).
 *
 * If the file value is an `Uint8Array`, assumes it is encoded in UTF-8.
 */
export function matter(file: VFile, customParser?: MDSXConfig['frontmatterParser']) {
	const doc = String(file);
	const a = performance.now();

	// use custom parser if provided
	if (customParser) {
		const parsed = customParser(doc);
		if (parsed) {
			file.data.matter = parsed;
		} else {
			file.data.matter = {};
		}
		logPerf('matter', a);
		return;
	}

	const match = regex.exec(String(file));

	if (match && match[1]) {
		file.data.matter = yaml.parse(match[1]);
		const stripped = doc.slice(match[0].length);
		file.value =
			file.value && typeof file.value === 'object' ? new TextEncoder().encode(stripped) : stripped;
	} else {
		file.data.matter = {};
	}
	logPerf('matter', a);
}
