import { toMarkdown } from 'mdast-util-to-markdown';
import { CONTINUE, SKIP, visit } from 'unist-util-visit';
import type { Paragraph, Root } from 'mdast';
import type { Transformer } from 'unified';

type MdastTransformer = Transformer<Root, Root>;

const SVELTE_LOGIC_BLOCK = /{[#:/@]\w+.*}/;
const ELEMENT_OR_COMPONENT = /<[A-Za-z]+[\s\S]*>/;

function isSvelteBlock(value: string): boolean {
	return SVELTE_LOGIC_BLOCK.test(value);
}

function isElementOrComponent(value: string): boolean {
	return ELEMENT_OR_COMPONENT.test(value);
}

/**
 * Covers the the case where we have an arbitrary svelte block
 * or a component/element at the beginning of a paragraph.
 *
 * @example
 * ```md
 * {#each items as item}
 * some item
 * {/each}
 * ```
 * or
 * ```md
 * <button on:click={() => console.log('howdy')}>click me</button>
 * ```
 * or
 * ```md
 * <Component>
 * 	Hello friend
 * </Component>
 * ```
 *
 * We don't want a paragraph tag wrapped around the entire block,
 * so we convert it to an html node.
 */
export function remarkCleanSvelte(): MdastTransformer {
	return async (tree) => {
		visit(tree, 'paragraph', (node) => {
			const firstChild = node.children[0];
			if (!firstChild) return CONTINUE;
			if (firstChild.type !== 'text' && firstChild.type !== 'html') return CONTINUE;

			if (isSvelteBlock(firstChild.value) || isElementOrComponent(firstChild.value)) {
				convertParagraphToHtml(node);
				return SKIP;
			}
		});
	};
}

/**
 * Convert paragraph nodes that _shouldn't_ be paragraphs to html nodes
 * so they can be rendered correctly.
 */
function convertParagraphToHtml(node: Paragraph) {
	let value = '';

	for (const child of node.children) {
		if (child.type === 'text' || child.type === 'html') {
			// text and html are at their final form, so we can just add them to the value
			value += child.value;
		} else {
			// for the remaining node types, we'll convert them back to markdown before
			// adding them to the value
			value += toMarkdown(child);
		}
	}

	// @ts-expect-error We're modifying the node type
	node.type = 'html';
	// @ts-expect-error The original node type doesn't have a value, but `"html"` does
	node.value = value;
}
